using Microsoft.Extensions.DependencyInjection;
using Microsoft.Extensions.Hosting;
using Microsoft.Extensions.Logging;

var builder = Host.CreateApplicationBuilder(args);

// Redirect all logging to stderr so it doesn't corrupt the stdio JSON-RPC stream
builder.Logging.ClearProviders();
builder.Logging.AddConsole(options => options.LogToStandardErrorThreshold = LogLevel.Trace);

builder.Services.AddHttpClient("ExternalApi", client =>
{
    client.BaseAddress = new Uri("https://api.example.com/");
});

builder.Services
    .AddMcpServer()
    .WithStdioServerTransport()
    .WithToolsFromAssembly()
    .WithPromptsFromAssembly();

var app = builder.Build();
await app.RunAsync();

using System.ComponentModel;
using System.Net.Http.Json;
using ModelContextProtocol.Server;

namespace McpServer.Tools;

[McpServerToolType]
public sealed class FetchDataTool
{
    [McpServerTool("fetch_data"), Description("Fetches data from an external API by resource path.")]
    public static async Task<string> FetchData(
        IHttpClientFactory httpClientFactory,
        [Description("The API resource path to fetch (e.g. 'users/1')")] string path,
        CancellationToken cancellationToken = default)
    {
        var client = httpClientFactory.CreateClient("ExternalApi");
        var response = await client.GetAsync(path, cancellationToken);
        response.EnsureSuccessStatusCode();
        var content = await response.Content.ReadAsStringAsync(cancellationToken);
        return content;
    }
}

using System.ComponentModel;
using ModelContextProtocol.Server;

namespace McpServer.Prompts;

[McpServerPromptType]
public sealed class SummarizePrompt
{
    [McpServerPrompt("summarize"), Description("Summarize the provided text concisely.")]
    public static IList<McpServerPromptMessage> Summarize(
        [Description("The text content to summarize")] string text,
        [Description("Optional desired length: short, medium, or long")] string length = "medium")
    {
        var systemInstruction = length switch
        {
            "short" => "Provide a 1-2 sentence summary.",
            "long" => "Provide a detailed multi-paragraph summary.",
            _ => "Provide a concise paragraph summary."
        };

        return
        [
            new McpServerPromptMessage
            {
                Role = Role.User,
                Content = new Content { Type = "text", Text = $"{systemInstruction}\n\nText to summarize:\n{text}" }
            }
        ];
    }
}

