using System.ComponentModel;
using System.Net.Http.Json;
using ModelContextProtocol.Server;

namespace McpServer.Tools;

[McpServerToolType]
public sealed class FetchDataTool
{
    [McpServerTool("fetch_data"), Description("Fetches data from an external API by resource path.")]
    public static async Task<string> FetchData(
        IHttpClientFactory httpClientFactory,
        [Description("The API resource path to fetch (e.g. 'users/1')")] string path,
        CancellationToken cancellationToken = default)
    {
        var client = httpClientFactory.CreateClient("ExternalApi");
        var response = await client.GetAsync(path, cancellationToken);
        response.EnsureSuccessStatusCode();
        var content = await response.Content.ReadAsStringAsync(cancellationToken);
        return content;
    }
}

