namespace McpServer.Prompts;

[McpServerPromptType]
public sealed class SummarizePrompt
{
    [McpServerPrompt("summarize"), Description("Summarize the provided text concisely.")]
    public static IList<McpServerPromptMessage> Summarize(
        [Description("The text content to summarize")] string text,
        [Description("Optional desired length: short, medium, or long")] string length = "medium")
    {
        var systemInstruction = length switch
        {
            "short" => "Provide a 1-2 sentence summary.",
            "long" => "Provide a detailed multi-paragraph summary.",
            _ => "Provide a concise paragraph summary."
        };

        return
        [
            new McpServerPromptMessage
            {
                Role = Role.User,
                Content = new Content { Type = "text", Text = $"{systemInstruction}\n\nText to summarize:\n{text}" }
            }
        ];
    }
}

